4	// All tests mock child_process.spawn so no real Claude is invoked.
5	
6	const { EventEmitter } = require('events');
7	
8	jest.mock('child_process', () => ({ spawn: jest.fn() }));
9	jest.mock('../../services/bot/src/notifier', () => ({
10	  notifyAuthExpired: jest.fn().mockResolvedValue(undefined),
11	}));
12	jest.mock('../../services/bot/src/logger', () => ({
13	  info: jest.fn(),
14	  warn: jest.fn(),
15	  error: jest.fn(),
16	}));
17	
18	// Build a fake child process that emits stdout/stderr/close on the next tick.
19	function fakeProc({ exitCode = 0, stdout = '', stderr = '' } = {}) {
20	  const proc = new EventEmitter();
21	  proc.stdout = new EventEmitter();
22	  proc.stderr = new EventEmitter();
23	  setImmediate(() => {
24	    if (stdout) proc.stdout.emit('data', Buffer.from(stdout));
25	    if (stderr) proc.stderr.emit('data', Buffer.from(stderr));
26	    proc.emit('close', exitCode);
27	  });
28	  return proc;
29	}
30	
31	// After jest.resetModules() we must re-require every mocked module to get
32	// fresh references — resetModules clears the registry but keeps mock factories.
33	function freshRequires(env = {}) {
34	  Object.assign(process.env, env);
35	  jest.resetModules();
36	  return {
37	    runClaude:         require('../../services/bot/src/claude-runner').runClaude,
38	    spawn:             require('child_process').spawn,
39	    notifyAuthExpired: require('../../services/bot/src/notifier').notifyAuthExpired,
40	    logger:            require('../../services/bot/src/logger'),
41	  };
42	}
43	
44	afterEach(() => {
45	  delete process.env.CLAUDE_SUBSCRIPTION_MODE;
46	  delete process.env.DRY_RUN;
47	  jest.clearAllMocks();
48	});
