55	  it('returns after one spawn when subscription succeeds (exit 0 + stdout)', async () => {
56	    const { runClaude, spawn } = freshRequires({ CLAUDE_SUBSCRIPTION_MODE: 'true' });
57	    spawn.mockReturnValueOnce(fakeProc({ exitCode: 0, stdout: 'research output' }));
58	
59	    await expect(runClaude('prompt', '/tmp', {})).resolves.toBeUndefined();
60	    expect(spawn).toHaveBeenCalledTimes(1);
61	  });
62	});
