91	    spawn
92	      .mockReturnValueOnce(fakeProc({ exitCode: 0, stdout: '', stderr: '' }))
93	      .mockReturnValueOnce(fakeProc({ exitCode: 0, stdout: 'api output' }));
94	
95	    await runClaude('prompt', '/tmp', {});
96	    const warnCall = logger.warn.mock.calls.find(c => c[0].includes('silently'));
97	    expect(warnCall).toBeDefined();
98	    expect(warnCall[0]).toMatch(/claude login/);
99	  });
100	
101	  it('throws when API key fallback also exits silently', async () => {
102	    const { runClaude, spawn } = freshRequires({ CLAUDE_SUBSCRIPTION_MODE: 'true' });
103	    spawn
104	      .mockReturnValueOnce(fakeProc({ exitCode: 0, stdout: '', stderr: '' }))  // subscription silent
